23 +import java.io.IOException;
24 +import java.math.BigInteger;
25 +
26 +/**
27 + *
28 + * @author rmartinc
29 + */
30 +class ASN1Encoder {
31 +
32 +    static final int INTEGER = 0x02;
33 +    static final int SEQUENCE = 0x10;
34 +    static final int CONSTRUCTED = 0x20;
35 +
36 +    private final ByteArrayOutputStream os;
37 +
38 +    private ASN1Encoder() {
39 +        this.os = new ByteArrayOutputStream();
40 +    }
41 +
42 +    static public ASN1Encoder create() {
43 +        return new ASN1Encoder();
44 +    }
45 +
46 +    public ASN1Encoder write(BigInteger value) throws IOException {
47 +        writeEncoded(INTEGER, value.toByteArray());
48 +        return this;
49 +    }
50 +
51 +    public ASN1Encoder writeDerSeq(ASN1Encoder... objects) throws IOException {
52 +        writeEncoded(CONSTRUCTED | SEQUENCE, concatenate(objects));
53 +        return this;
54 +    }
55 +
56 +    public byte[] toByteArray() {
57 +        return os.toByteArray();
58 +    }
59 +
60 +    void writeEncoded(int tag, byte[] bytes) throws IOException {
61 +        write(tag);
62 +        writeLength(bytes.length);
63 +        write(bytes);
64 +    }
65 +
66 +    void writeLength(int length) throws IOException {
67 +        if (length > 127) {
68 +            int size = 1;
69 +            int val = length;
70 +
71 +            while ((val >>>= 8) != 0) {
72 +                size++;
73 +            }
74 +
75 +            write((byte) (size | 0x80));
76 +
77 +            for (int i = (size - 1) * 8; i >= 0; i -= 8) {
78 +                write((byte) (length >> i));
79 +            }
80 +        } else {
81 +            write((byte) length);
82 +        }
83 +    }
84 +
85 +    void write(byte[] bytes) throws IOException {
86 +        os.write(bytes);
87 +    }
88 +
89 +    void write(int b) throws IOException {
90 +        os.write(b);
91 +    }
92 +
93 +    byte[] concatenate(ASN1Encoder... objects) throws IOException {
94 +        ByteArrayOutputStream tmp = new ByteArrayOutputStream();
95 +        for (ASN1Encoder object : objects) {
96 +            tmp.write(object.toByteArray());
97 +        }
98 +        return tmp.toByteArray();
99 +    }
100 +}
